actions.script:
import org.moqui.agent.AgentConfigUtil
document = (document ?: [:]) as Map
if (!document._type) document._type = dataDocumentId
if (!document._id && document.documentId) document._id = document.documentId
if (!document._index) document._index = AgentConfigUtil.getString('moqui.agent.prompt.indexName', 'moqui_agent_prompts_v1')
if (!document._timestamp) document._timestamp = ec.l10n.format(ec.user.nowTimestamp, "yyyy-MM-dd'T'HH:mm:ss")

document = (document ?: [:]) as Map
if (!document._type) document._type = dataDocumentId
if (!document._id && document.documentId) document._id = document.documentId
if (!document._index) {
    Map projectionIndexByDocument = [
        AgentArtifactDocument   : 'moqui_agent_documents_v2',
        AgentGraphVertexDocument: 'moqui_agent_graph_vertices_v1',
        AgentGraphEdgeDocument  : 'moqui_agent_graph_edges_v1'
    ]
    document._index = projectionIndexByDocument.get(dataDocumentId, 'moqui_agent_documents_v2')
}
if (!document._timestamp) document._timestamp = ec.l10n.format(ec.user.nowTimestamp, "yyyy-MM-dd'T'HH:mm:ss")

import org.moqui.agent.AgentConfigUtil
import org.moqui.agent.model.AgentModelFacade

Map doc = (document ?: [:]) as Map
String docType = (dataDocumentId ?: '').toString()
List<Map> parameterList = (doc.parameters instanceof List ? (doc.parameters as List<Map>) : []) ?: []
Map<String, String> parameterByDef = [:]
parameterList.each { Map param ->
    String defId = (param?.parameterDefId ?: '').toString()
    String paramValue = ((param?.textValue ?: param?.symbolicValue ?: '') as String).toString()
    if (defId && !parameterByDef.containsKey(defId)) parameterByDef.put(defId, paramValue)
}
Closure<String> firstValue = { String currentValue, String parameterDefId ->
    String existing = (currentValue ?: '').toString()
    if (existing) return existing
    return (parameterByDef[parameterDefId] ?: '').toString()
}

String vertexType = firstValue(doc.vertexType as String, 'AgGraphVertexTypeParam')
String sourceArtifactUri = firstValue(doc.sourceArtifactUri as String, 'AgGraphSourceArtifactUriParam')
String label = (doc.label ?: '').toString()
String graphVertexId = (doc.graphVertexId ?: '').toString()
String sourceVertexId = firstValue(doc.sourceVertexId as String, 'AgGraphSourceVertexIdParam')
String artifactKind = firstValue(doc.artifactKind as String, 'AgGraphArtifactKindParam')
String screenPath = firstValue(doc.screenPath as String, 'AgGraphScreenPathParam')
String serviceName = firstValue(doc.serviceName as String, 'AgGraphServiceNameParam')
String serviceVerb = firstValue(doc.serviceVerb as String, 'AgGraphServiceVerbParam')
String serviceNoun = firstValue(doc.serviceNoun as String, 'AgGraphServiceNounParam')
String entityName = firstValue(doc.entityName as String, 'AgGraphEntityNameParam')
String fieldName = firstValue(doc.fieldName as String, 'AgGraphFieldNameParam')
String documentType = firstValue(doc.documentType as String, 'AgGraphDocumentTypeParam')
String xmlActionElement = firstValue(doc.xmlActionElement as String, 'AgGraphXmlActionElementParam')
String domainObjectValue = firstValue(doc.domainObject as String, 'AgGraphDomainObjectParam')
String subjectValue = firstValue(doc.subject as String, 'AgGraphSubjectParam')
String operationValue = firstValue(doc.operation as String, 'AgGraphOperationParam')
String calledServiceValue = firstValue(doc.calledService as String, 'AgGraphCalledServiceParam')
String parameterRoleValue = firstValue(doc.parameterRole as String, 'AgGraphParameterRoleParam')

Closure<List<String>> splitNonEmpty = { Object rawValue ->
    String text = (rawValue ?: '').toString()
    if (!text) return []
    return text.split(/[\\s,;:()\\/._#-]+/)
            .collect { it?.trim() }
            .findAll { it }
}
Closure<String> safeJoin = { Collection values ->
    return values?.findAll { it != null && it.toString().trim() }
            ?.collect { it.toString().trim() }
            ?.unique()
            ?.join(' | ') ?: ''
}
Closure<Map> parseArtifactLocation = {
    String componentName = ''
    String area = ''
    String subArea = ''
    String namespace = ''
    String location = sourceArtifactUri ?: screenPath ?: ''
    if (location.startsWith('component://')) {
        String noScheme = location.substring('component://'.length())
        List<String> segs = noScheme.tokenize('/')
        if (segs) componentName = segs[0]
        String fileName = segs ? segs[-1] : ''
        if (fileName) subArea = fileName.replaceFirst(/\.[^.]+$/, '')
        int markerIndex = segs.findIndexOf { it in ['screen', 'service', 'entity', 'data', 'xsd', 'src'] }
        List<String> domainSegs = []
        if (markerIndex > 0) {
            domainSegs = segs.subList(1, markerIndex)
            if (!domainSegs && segs.size() > markerIndex + 2) {
                domainSegs = segs.subList(markerIndex + 1, segs.size() - 1)
            }
        } else if (segs.size() > 1) {
            domainSegs = segs.subList(1, segs.size() - 1)
        }
        namespace = domainSegs.join('.')
        area = namespace ?: componentName
    } else if (location.contains('/runtime/component/')) {
        String noPrefix = location.substring(location.indexOf('/runtime/component/') + '/runtime/component/'.length())
        List<String> segs = noPrefix.tokenize('/')
        if (segs) componentName = segs[0]
        String fileName = segs ? segs[-1] : ''
        if (fileName) subArea = fileName.replaceFirst(/\.[^.]+$/, '')
        int markerIndex = segs.findIndexOf { it in ['screen', 'service', 'entity', 'data', 'xsd', 'src'] }
        List<String> domainSegs = []
        if (markerIndex > 0) {
            domainSegs = segs.subList(1, markerIndex)
            if (!domainSegs && segs.size() > markerIndex + 2) {
                domainSegs = segs.subList(markerIndex + 1, segs.size() - 1)
            }
        } else if (segs.size() > 1) {
            domainSegs = segs.subList(1, segs.size() - 1)
        }
        namespace = domainSegs.join('.')
        area = namespace ?: componentName
    }
    return [componentName: componentName, area: area, subArea: subArea, namespace: namespace]
}

Closure<Map> deriveTaxonomy = {
    String componentName = ''
    String area = ''
    String subArea = ''
    String namespace = ''

    Map locationInfo = parseArtifactLocation()
    componentName = (locationInfo.componentName ?: '') as String
    area = (locationInfo.area ?: '') as String
    subArea = (locationInfo.subArea ?: '') as String
    namespace = (locationInfo.namespace ?: '') as String

    if ((!namespace || !subArea) && serviceName) {
        List<String> segs = serviceName.tokenize('.')
        if (segs.size() >= 2) {
            String tail = segs[-1]
            String artifactStem = tail.contains('#') ? tail.substring(0, tail.indexOf('#')) : tail
            int createMarker = segs.findIndexOf { it.contains('#') || it ==~ /[a-z][A-Za-z0-9_]*/ }
            if (!subArea) {
                String parentArtifact = segs.size() >= 2 ? segs[-2] : artifactStem
                subArea = parentArtifact
            }
            if (!namespace && segs.size() > 2) {
                namespace = segs.subList(0, Math.max(0, segs.size() - 2)).join('.')
            }
            if (!area && namespace) {
                List<String> nsSegs = namespace.tokenize('.')
                area = nsSegs.size() >= 2 ? nsSegs.subList(0, 2).join('.') : namespace
            }
        }
    }

    if ((!namespace || !subArea || !area) && entityName) {
        List<String> segs = entityName.tokenize('.')
        if (!subArea && segs) subArea = segs[-1]
        if (!namespace && segs.size() > 1) namespace = segs.subList(0, segs.size() - 1).join('.')
        if (!area && namespace) {
            List<String> nsSegs = namespace.tokenize('.')
            area = nsSegs.size() >= 2 ? nsSegs.subList(0, 2).join('.') : namespace
        }
    }

    if ((!subArea || !area) && screenPath) {
        String screenName = screenPath.tokenize('/').last()
        if (!subArea && screenName) subArea = screenName.replaceFirst(/\.[^.]+$/, '')
    }

    if (!area && componentName) area = componentName
    return [componentName: componentName, area: area, subArea: subArea, namespace: namespace]
}

Map locationInfo = deriveTaxonomy()
String componentName = locationInfo.componentName as String
String area = locationInfo.area as String
String subArea = locationInfo.subArea as String
String namespace = locationInfo.namespace as String
String businessObject = (entityName ?: domainObjectValue ?: '').toString()
if (!serviceVerb && serviceName?.contains('.')) {
    String tail = serviceName.tokenize('.').last()
    if (tail.contains('#')) serviceVerb = tail.substring(0, tail.indexOf('#'))
}
if (!serviceNoun && serviceName?.contains('#')) {
    serviceNoun = serviceName.substring(serviceName.indexOf('#') + 1)
}
if (!businessObject && serviceNoun) businessObject = serviceNoun
String verb = (serviceVerb ?: operationValue ?: xmlActionElement ?: '').toString()
String noun = (serviceNoun ?: '').toString()
String audience = 'developer'
boolean runtimeExecutable = false
boolean knowledgeOnly = true
if (docType == 'AgentArtifactVertexDocument') {
    if (['Screen', 'Form', 'Transition'].contains(vertexType)) {
        audience = 'generic_user'
        runtimeExecutable = true
        knowledgeOnly = false
    } else if (['Service'].contains(vertexType)) {
        audience = 'developer'
        runtimeExecutable = true
        knowledgeOnly = false
    }
}
if (docType in ['AgentArtifactScreen', 'AgentArtifactForm', 'AgentArtifactTransition']) {
    audience = 'generic_user'
    runtimeExecutable = true
    knowledgeOnly = false
} else if (docType in ['AgentArtifactService', 'AgentArtifactOperationPattern']) {
    audience = 'developer'
    runtimeExecutable = true
    knowledgeOnly = false
} else if (docType in ['AgentArtifactXsdSchema', 'AgentArtifactXsdElement', 'AgentArtifactXmlAction', 'AgentArtifactEntity', 'AgentArtifactServiceParameter']) {
    audience = 'developer'
    runtimeExecutable = false
    knowledgeOnly = true
}

String displayLabel = label
if ((!displayLabel || displayLabel.startsWith('/')) && screenPath) {
    displayLabel = screenPath.tokenize('/').last()?.replaceFirst(/\.[^.]+$/, '')
}
if ((!displayLabel || displayLabel.startsWith('/')) && serviceName) displayLabel = serviceName
if ((!displayLabel || displayLabel.startsWith('/')) && entityName) displayLabel = entityName
if ((!displayLabel || displayLabel.startsWith('/')) && xmlActionElement) displayLabel = xmlActionElement
String artifactLabel = displayLabel ?: label ?: graphVertexId
String title = artifactLabel
List<String> promptParts = []
List<String> explanationParts = []
List<String> enVariants = []
List<String> itVariants = []
List<String> uiLabels = [displayLabel, label, screenPath, serviceName, entityName, fieldName]
        .findAll { it != null && it.toString().trim() }
        .collect { it.toString().trim() }
List<String> fieldNames = [fieldName].findAll { it != null && it.toString().trim() }.collect { it.toString().trim() }
List<String> relatedEntities = [entityName, domainObjectValue].findAll { it != null && it.toString().trim() }.collect { it.toString().trim() }.unique()
List<String> boundServices = [serviceName, calledServiceValue].findAll { it != null && it.toString().trim() }.collect { it.toString().trim() }.unique()

switch (docType) {
    case 'AgentArtifactVertexDocument':
        promptParts.addAll([artifactLabel, vertexType, serviceName, serviceVerb, serviceNoun, entityName, domainObjectValue, subjectValue, operationValue, screenPath, xmlActionElement])
        explanationParts.addAll([
                "Artifact ${artifactLabel}",
                vertexType ? "vertex type ${vertexType}" : '',
                artifactKind ? "artifact kind ${artifactKind}" : '',
                serviceName ? "service ${serviceName}" : '',
                entityName ? "entity ${entityName}" : '',
                screenPath ? "screen ${screenPath}" : '',
                xmlActionElement ? "xml action ${xmlActionElement}" : ''
        ])
        enVariants.addAll([
                serviceName ?: '',
                entityName ? "what is ${entityName}" : '',
                screenPath ? "open ${screenPath}" : '',
                xmlActionElement ? "how does ${xmlActionElement} work" : ''
        ])
        itVariants.addAll([
                serviceName ?: '',
                entityName ? "cos'è ${entityName}" : '',
                screenPath ? "apri ${screenPath}" : '',
                xmlActionElement ? "come funziona ${xmlActionElement}" : ''
        ])
        break
    case 'AgentArtifactScreen':
        promptParts.addAll([artifactLabel, screenPath, businessObject, 'screen'])
        explanationParts.addAll([
                "Screen ${artifactLabel}",
                screenPath ? "path ${screenPath}" : '',
                businessObject ? "business object ${businessObject}" : '',
                area ? "area ${area}" : ''
        ])
        enVariants.addAll([
                "open ${artifactLabel}",
                businessObject ? "open ${businessObject} screen" : '',
                screenPath ? "show screen ${screenPath}" : ''
        ])
        itVariants.addAll([
                "apri ${artifactLabel}",
                businessObject ? "apri schermata ${businessObject}" : '',
                screenPath ? "mostra schermata ${screenPath}" : ''
        ])
        break
    case 'AgentArtifactForm':
        promptParts.addAll([artifactLabel, screenPath, businessObject, 'form'])
        explanationParts.addAll([
                "Form ${artifactLabel}",
                screenPath ? "screen ${screenPath}" : '',
                businessObject ? "for ${businessObject}" : ''
        ])
        enVariants.addAll([
                "fill form ${artifactLabel}",
                businessObject ? "enter ${businessObject} data" : ''
        ])
        itVariants.addAll([
                "compila form ${artifactLabel}",
                businessObject ? "inserisci dati ${businessObject}" : ''
        ])
        break
    case 'AgentArtifactTransition':
        promptParts.addAll([artifactLabel, screenPath, serviceName, verb, noun, businessObject, 'transition'])
        explanationParts.addAll([
                "Transition ${artifactLabel}",
                screenPath ? "from screen ${screenPath}" : '',
                serviceName ? "calls ${serviceName}" : '',
                verb ? "verb ${verb}" : '',
                noun ? "noun ${noun}" : ''
        ])
        enVariants.addAll([
                artifactLabel ? "use ${artifactLabel}" : '',
                verb && noun ? "${verb} ${noun}" : '',
                businessObject && verb ? "${verb} ${businessObject}" : ''
        ])
        itVariants.addAll([
                artifactLabel ? "usa ${artifactLabel}" : '',
                verb && noun ? "${verb} ${noun}" : '',
                businessObject && verb ? "${verb} ${businessObject}" : ''
        ])
        break
    case 'AgentArtifactService':
    case 'AgentArtifactOperationPattern':
        promptParts.addAll([serviceName, verb, noun, businessObject, subjectValue, parameterRoleValue])
        explanationParts.addAll([
                "Service ${serviceName ?: artifactLabel}",
                verb ? "verb ${verb}" : '',
                noun ? "noun ${noun}" : '',
                businessObject ? "domain object ${businessObject}" : '',
                subjectValue ? "subject ${subjectValue}" : ''
        ])
        enVariants.addAll([
                serviceName ?: '',
                verb && noun ? "${verb} ${noun}" : '',
                businessObject && verb ? "${verb} ${businessObject}" : ''
        ])
        itVariants.addAll([
                serviceName ?: '',
                verb && noun ? "${verb} ${noun}" : '',
                businessObject && verb ? "${verb} ${businessObject}" : ''
        ])
        break
    case 'AgentArtifactXmlAction':
        promptParts.addAll([artifactLabel, xmlActionElement, serviceName, entityName, fieldName, calledServiceValue, subjectValue, operationValue])
        explanationParts.addAll([
                "XML action ${artifactLabel}",
                serviceName ? "inside ${serviceName}" : '',
                entityName ? "entity ${entityName}" : '',
                fieldName ? "field ${fieldName}" : '',
                calledServiceValue ? "calls ${calledServiceValue}" : ''
        ])
        enVariants.addAll([
                xmlActionElement ? "how does ${xmlActionElement} work" : '',
                calledServiceValue ? "where is ${calledServiceValue} called" : '',
                entityName ? "where is entity ${entityName} used" : ''
        ])
        itVariants.addAll([
                xmlActionElement ? "come funziona ${xmlActionElement}" : '',
                calledServiceValue ? "dove viene chiamato ${calledServiceValue}" : '',
                entityName ? "dove viene usata entity ${entityName}" : ''
        ])
        break
    case 'AgentArtifactServiceParameter':
        promptParts.addAll([artifactLabel, serviceName, parameterRoleValue, subjectValue, businessObject])
        explanationParts.addAll([
                "Service parameter ${artifactLabel}",
                serviceName ? "of ${serviceName}" : '',
                parameterRoleValue ? "role ${parameterRoleValue}" : '',
                subjectValue ? "subject ${subjectValue}" : ''
        ])
        enVariants.addAll([
                serviceName && artifactLabel ? "parameter ${artifactLabel} of ${serviceName}" : '',
                serviceName && parameterRoleValue ? "${parameterRoleValue} parameters of ${serviceName}" : ''
        ])
        itVariants.addAll([
                serviceName && artifactLabel ? "parametro ${artifactLabel} di ${serviceName}" : '',
                serviceName && parameterRoleValue ? "parametri ${parameterRoleValue} di ${serviceName}" : ''
        ])
        break
    case 'AgentArtifactEntity':
        promptParts.addAll([entityName, fieldName, businessObject, 'entity'])
        explanationParts.addAll([
                "Entity ${entityName ?: artifactLabel}",
                fieldName ? "field ${fieldName}" : '',
                area ? "area ${area}" : ''
        ])
        enVariants.addAll([
                entityName ? "what is entity ${entityName}" : '',
                fieldName && entityName ? "field ${fieldName} of ${entityName}" : ''
        ])
        itVariants.addAll([
                entityName ? "cos'è la entity ${entityName}" : '',
                fieldName && entityName ? "campo ${fieldName} di ${entityName}" : ''
        ])
        break
    case 'AgentArtifactXsdElement':
    case 'AgentArtifactXsdSchema':
        promptParts.addAll([artifactLabel, xmlActionElement, sourceArtifactUri, entityName, fieldName])
        explanationParts.addAll([
                "XSD artifact ${artifactLabel}",
                xmlActionElement ? "element ${xmlActionElement}" : '',
                sourceArtifactUri ? "from ${sourceArtifactUri}" : ''
        ])
        enVariants.addAll([
                artifactLabel ? "xsd definition for ${artifactLabel}" : '',
                xmlActionElement ? "xml-actions element ${xmlActionElement}" : ''
        ])
        itVariants.addAll([
                artifactLabel ? "definizione xsd di ${artifactLabel}" : '',
                xmlActionElement ? "elemento xml-actions ${xmlActionElement}" : ''
        ])
        break
}

String canonicalPrompt = safeJoin(promptParts)
String humanExplanation = safeJoin(explanationParts)
String englishPromptVariants = enVariants.findAll { it } .unique().join('\n')
String italianPromptVariants = itVariants.findAll { it } .unique().join('\n')
String uiLabelsText = uiLabels.unique().join('\n')
String embeddingText = safeJoin([
        title,
        vertexType,
        area,
        subArea,
        namespace,
        businessObject,
        verb,
        noun,
        xmlActionElement,
        serviceName,
        entityName,
        fieldName,
        subjectValue,
        parameterRoleValue,
        operationValue,
        calledServiceValue,
        humanExplanation,
        englishPromptVariants,
        italianPromptVariants,
        uiLabelsText
])

doc.documentId = "${docType}:${graphVertexId}"
doc.documentKind = audience
doc.projectionDocumentType = docType
doc.sourceGraphId = doc.graphId
doc.sourceVertexId = graphVertexId
doc.sourceArtifactUri = sourceArtifactUri
doc.sourceVertexId = sourceVertexId ?: graphVertexId
doc.vertexType = vertexType
doc.artifactKind = artifactKind
doc.screenPath = screenPath
doc.serviceName = serviceName
doc.serviceVerb = serviceVerb
doc.serviceNoun = serviceNoun
doc.entityName = entityName
doc.fieldName = fieldName
doc.documentType = documentType
doc.xmlActionElement = xmlActionElement
doc.domainObject = domainObjectValue
doc.subject = subjectValue
doc.operation = operationValue
doc.calledService = calledServiceValue
doc.parameterRole = parameterRoleValue
doc.area = area
doc.subArea = subArea
doc.domainObject = businessObject
doc.component = componentName
doc.namespace = namespace
doc.verb = verb
doc.runtimeExecutable = runtimeExecutable
doc.knowledgeOnly = knowledgeOnly
doc.canonicalPrompt = canonicalPrompt
doc.embeddingText = embeddingText
doc.humanExplanation = humanExplanation
doc.englishPromptVariants = englishPromptVariants
doc.italianPromptVariants = italianPromptVariants
doc.uiLabels = uiLabelsText
doc.fieldNames = fieldNames
doc.relatedEntities = relatedEntities
doc.boundServices = boundServices
doc.sourceScreenPath = screenPath
if (doc.parameters) doc.remove('parameters')
doc._type = docType
doc._id = doc.documentId
doc._index = 'moqui_agent_documents_v2'
if (!doc._timestamp) doc._timestamp = ec.l10n.format(ec.user.nowTimestamp, "yyyy-MM-dd'T'HH:mm:ss")

String provider = AgentConfigUtil.getString('moqui.agent.embedding.provider', 'none')
if (embeddingText && provider && provider != 'none') {
    try {
        Map emb = new AgentModelFacade(ec).embed(embeddingText, [
                provider: provider,
                model: AgentConfigUtil.getString('moqui.agent.embedding.model', 'text-embedding-3-large'),
                dimensions: AgentConfigUtil.getInt('moqui.agent.embedding.dimensions', 3072, 1)
        ])
        if (emb?.embedding instanceof List && emb.embedding) {
            doc.embedding = emb.embedding
        }
    } catch (Throwable t) {
        ec.logger.warn("Failed to embed ${doc.documentId}: ${t.message}")
    }
}

document = doc

import groovy.json.JsonOutput import groovy.json.JsonSlurper import java.security.MessageDigest import org.moqui.entity.EntityCondition import org.moqui.agent.AgentConfigUtil import org.moqui.agent.model.AgentModelFacade import org.moqui.jcache.MCache
String provider = (embeddingProvider ?: AgentConfigUtil.getString('moqui.agent.embedding.provider', 'none')).toString().trim().toLowerCase() String model = (embeddingModel ?: AgentConfigUtil.getString('moqui.agent.embedding.model', 'text-embedding-3-large')).toString() Integer dimensions = (embeddingDimensions ?: AgentConfigUtil.getInt('moqui.agent.embedding.dimensions', 3072, 1)) as Integer String normalizedText = (queryText ?: '').trim().replaceAll(/\s+/, ' ').toLowerCase() boolean cacheQueryText = AgentConfigUtil.getBoolean('moqui.agent.embedding.cacheQueryText', false) MCache l1EmbeddingCache = ec.cache.getLocalCache('agent.query.embedding.l1')
providerUsed = provider modelUsed = model dimensionsUsed = dimensions embedding = [] cacheHit = false if (!normalizedText || provider == 'none') return
String cacheKeySource = "${provider}|${model}|${dimensions}|${normalizedText}" // cacheKey is stored in an entity PK field of length 40, so use SHA-1 hex // (40 chars) for schema compatibility instead of SHA-256 hex (64 chars). MessageDigest md = MessageDigest.getInstance('SHA-1') String cacheKey = md.digest(cacheKeySource.getBytes('UTF-8')).encodeHex().toString()
List l1CachedEmbedding = (List) l1EmbeddingCache.get(cacheKey) if (l1CachedEmbedding) { embedding = l1CachedEmbedding cacheHit = true return }
def cacheValue = ec.entity.find('moqui.rag.ArtifactQueryEmbeddingCache') .condition('cacheKey', cacheKey) .one() if (cacheValue?.embeddingJson) { embedding = (List) new JsonSlurper().parseText(cacheValue.embeddingJson as String) cacheHit = true l1EmbeddingCache.put(cacheKey, new ArrayList(embedding)) cacheValue.lastUsedDate = ec.user.nowTimestamp cacheValue.hitCount = ((cacheValue.hitCount ?: 0) as Integer) + 1 cacheValue.update() return }
Map embeddingResult = new AgentModelFacade(ec).embed(queryText, [ provider : provider, model : model, dimensions : dimensions ]) embedding = (embeddingResult.embedding instanceof List) ? (embeddingResult.embedding as List) : []
if (!embedding) return l1EmbeddingCache.put(cacheKey, new ArrayList(embedding))
def newCacheValue = ec.entity.makeValue('moqui.rag.ArtifactQueryEmbeddingCache') newCacheValue.setAll([ cacheKey : cacheKey, queryTextNorm : cacheQueryText ? normalizedText : null, embeddingProvider : provider, embeddingModel : model, embeddingDimensions: dimensions, embeddingJson : JsonOutput.toJson(embedding), createdDate : ec.user.nowTimestamp, lastUsedDate : ec.user.nowTimestamp, hitCount : 1 ]) newCacheValue.create()

import org.moqui.agent.AgentConfigUtil import groovy.json.JsonSlurper
def ref = ec.resource.getLocationReference('component://moqui-mcp/tools/agent-indexer/opensearch-mapping-agent-area.json') Map mappingFile = (Map) new JsonSlurper().parseText(ref.getText()) settings = ((mappingFile['settings'] ?: [:]) as Map) mapping = ((mappingFile['mappings'] ?: [:]) as Map)
Integer dimensions = AgentConfigUtil.getInt('moqui.agent.embedding.dimensions', 3072, 1) Map mappingProperties = (mapping instanceof Map) ? ((mapping['properties'] ?: [:]) as Map) : [:] if (mappingProperties['embedding'] instanceof Map) { Map embeddingField = new LinkedHashMap((mappingProperties['embedding'] ?: [:]) as Map) embeddingField['dimension'] = dimensions mappingProperties['embedding'] = embeddingField mapping['properties'] = mappingProperties }

import org.moqui.agent.AgentConfigUtil import groovy.json.JsonSlurper
def ref = ec.resource.getLocationReference('component://moqui-mcp/tools/agent-indexer/opensearch-mapping-agent-projection.json') Map mappingFile = (Map) new JsonSlurper().parseText(ref.getText()) settings = ((mappingFile['settings'] ?: [:]) as Map) mapping = ((mappingFile['mappings'] ?: [:]) as Map)
Integer dimensions = AgentConfigUtil.getInt('moqui.agent.embedding.dimensions', 3072, 1) Map mappingProperties = (mapping instanceof Map) ? ((mapping['properties'] ?: [:]) as Map) : [:] if (mappingProperties['embedding'] instanceof Map) { Map embeddingField = new LinkedHashMap((mappingProperties['embedding'] ?: [:]) as Map) embeddingField['dimension'] = dimensions mappingProperties['embedding'] = embeddingField mapping['properties'] = mappingProperties }

List<String> dataDocumentIds = [ 'AgentArtifactVertexDocument', 'AgentArtifactScreen', 'AgentArtifactForm', 'AgentArtifactService', 'AgentArtifactOperationPattern', 'AgentArtifactXmlAction', 'AgentArtifactTransition', 'AgentArtifactServiceParameter', 'AgentArtifactEntity', 'AgentArtifactXsdElement', 'AgentArtifactXsdSchema' ] String dataFeedId = 'AgentArtifactGraphFeed'
ec.entity.find('moqui.entity.feed.DataFeedDocument') .condition('dataFeedId', dataFeedId) .deleteAll() ec.entity.find('moqui.entity.feed.DataFeed') .condition('dataFeedId', dataFeedId) .deleteAll()
