import groovy.json.JsonOutput import groovy.json.JsonSlurper import java.security.MessageDigest
String effectiveGraphId = (graphId ?: 'AgentArtifactGraph').toString() String effectiveMathModelId = (mathModelId ?: 'AgentMoquiRagModel_v1').toString() String effectiveGraphName = (graphName ?: 'Agent Artifact Graph').toString() String effectiveGraphDescription = (graphDescription ?: 'Materialized structural graph for offline-generated Moqui agent artifacts.').toString() String effectiveGraphTypeEnumId = graphTypeEnumId ? graphTypeEnumId.toString() : null boolean shouldCreateMathModelRun = (createMathModelRun == null) ? true : Boolean.TRUE.equals(createMathModelRun) if (!mathModelRunId && shouldCreateMathModelRun) { Map runResult = ec.service.sync().name('org.moqui.agent.AgentMathModelServices.create#AgentMathModelRun') .parameters([ mathModelId : effectiveMathModelId, runTypeEnumId : 'AgentRunArtifactGraphLoad', runName : 'Artifact Graph Load', sourceServiceName : 'org.moqui.agent.AgentDocumentServices.load#ArtifactGraph', parametersJson : JsonOutput.toJson([ graphId : effectiveGraphId, verticesFilePath : verticesFilePath, edgesFilePath : edgesFilePath, summaryFilePath : summaryFilePath, clearExisting : clearExisting ]) ]).call() mathModelRunId = runResult.mathModelRunId } MessageDigest vertexIdDigest = MessageDigest.getInstance('SHA-1') MessageDigest edgeIdDigest = MessageDigest.getInstance('SHA-1') Closure<String> normalizeVertexId = { String rawId -> String text = (rawId ?: '').toString() if (!text) return text return vertexIdDigest.digest("${effectiveGraphId}|${text}".getBytes('UTF-8')).encodeHex().toString() } Closure<String> normalizeEdgeId = { String rawId -> String text = (rawId ?: '').toString() if (!text) return text return edgeIdDigest.digest("${effectiveGraphId}|${text}".getBytes('UTF-8')).encodeHex().toString() } Closure<String> normalizeLabel = { Object rawLabel -> String text = (rawLabel ?: '').toString() if (!text) return text return text.length() > 63 ? (text.substring(0, 60) + '...') : text } Closure<String> normalizeSizedText = { Object rawValue, int maxLength -> String text = (rawValue ?: '').toString() if (!text || text.length() <= maxLength) return text String hash = MessageDigest.getInstance('SHA-1').digest(text.getBytes('UTF-8')).encodeHex().toString() String suffix = '-' + hash.substring(0, Math.min(12, hash.length())) int prefixLength = Math.max(0, maxLength - suffix.length()) return text.substring(0, prefixLength) + suffix } Map<String, String> vertexParameterDefByKey = [ graphVertexType : 'AgGraphVertexTypeParam', sourceVertexId : 'AgGraphSourceVertexIdParam', sourceArtifactUri : 'AgGraphSourceArtifactUriParam', artifactKind : 'AgGraphArtifactKindParam', screenPath : 'AgGraphScreenPathParam', serviceName : 'AgGraphServiceNameParam', serviceVerb : 'AgGraphServiceVerbParam', serviceNoun : 'AgGraphServiceNounParam', entityName : 'AgGraphEntityNameParam', fieldName : 'AgGraphFieldNameParam', documentType : 'AgGraphDocumentTypeParam', xmlActionElement : 'AgGraphXmlActionElementParam', domainObject : 'AgGraphDomainObjectParam', subject : 'AgGraphSubjectParam', operation : 'AgGraphOperationParam', calledService : 'AgGraphCalledServiceParam', parameterRole : 'AgGraphParameterRoleParam' ] Map<String, String> edgeParameterDefByKey = [ sourceEdgeId : 'AgGraphSourceEdgeIdParam', edgeRelation : 'AgGraphEdgeRelationParam', serviceName : 'AgGraphServiceNameParam', entityName : 'AgGraphEntityNameParam', fieldName : 'AgGraphFieldNameParam', edgeRole : 'AgGraphEdgeRoleParam' ] Closure<String> normalizeVertexType = { Object rawType -> String text = (rawType ?: '').toString().trim() if (!text) return 'Unknown' switch (text) { case 'ScreenTransition': return 'Transition' case 'ServiceActionStatement': return 'XmlAction' default: return text } } Closure<String> makeParameterId = { String parameterDefId, String graphVertexId, String graphEdgeId -> String source = "${effectiveGraphId}|${graphVertexId ?: ''}|${graphEdgeId ?: ''}|${parameterDefId}" return MessageDigest.getInstance('SHA-1').digest(source.getBytes('UTF-8')).encodeHex().toString() } Set<String> emittedParameterIds = new LinkedHashSet<String>() Closure<Void> storeGraphParameter = { String parameterDefId, Object rawValue, String graphVertexId, String graphEdgeId, int sequenceNum -> String textValue = (rawValue ?: '').toString() if (!textValue) return String symbolicValue = normalizeSizedText(textValue, 63) String parameterId = makeParameterId(parameterDefId, graphVertexId, graphEdgeId) if (emittedParameterIds.contains(parameterId)) return emittedParameterIds.add(parameterId) boolean alwaysCreate = Boolean.TRUE.equals(clearExisting) def parameterValue = null boolean newParameter = true if (!alwaysCreate) { parameterValue = ec.entity.find('moqui.math.Parameter').condition('parameterId', parameterId).one() newParameter = parameterValue == null if (parameterValue) parameterValue = parameterValue.cloneValue() } if (!parameterValue) { parameterValue = ec.entity.makeValue('moqui.math.Parameter') parameterValue.parameterId = parameterId } parameterValue.parameterDefId = parameterDefId parameterValue.mathModelId = effectiveMathModelId parameterValue.graphId = effectiveGraphId parameterValue.graphVertexId = graphVertexId parameterValue.graphEdgeId = graphEdgeId parameterValue.sequenceNum = sequenceNum parameterValue.symbolicValue = symbolicValue parameterValue.textValue = textValue if (newParameter) parameterValue.create() else parameterValue.update() }
