if (Boolean.TRUE.equals(clearExisting)) { ec.entity.find('moqui.math.Parameter') .condition('graphId', effectiveGraphId) .deleteAll() ec.entity.find('moqui.math.GraphEdge') .condition('graphId', effectiveGraphId) .deleteAll() ec.entity.find('moqui.math.GraphVertex') .condition('graphId', effectiveGraphId) .deleteAll() ec.entity.find('moqui.math.GraphContent') .condition('graphId', effectiveGraphId) .deleteAll() }
