Map<String, Object> vertexParameters = [ graphVertexType : normalizeVertexType(vertex.vertexType ?: vertex.type), sourceVertexId : rawVertexId, sourceArtifactUri : (vertex.sourceArtifactUri ?: vertex.artifactUri ?: vertex.sourceUri ?: rawVertexId), artifactKind : (vertex.sourceArtifactKind ?: vertex.artifactType ?: vertex.vertexType ?: vertex.type ?: ''), screenPath : (vertex.sourceScreenPath ?: vertex.screenPath ?: ''), serviceName : (vertex.serviceName ?: vertex.artifactName ?: ''), serviceVerb : (vertex.serviceVerb ?: ''), serviceNoun : (vertex.serviceNoun ?: ''), entityName : (vertex.entityName ?: ''), fieldName : (vertex.fieldName ?: ''), documentType : (vertex.documentType ?: vertex.documentKind ?: ''), xmlActionElement : (vertex.xmlActionElement ?: vertex.statementClass ?: ''), domainObject : (vertex.domainObject ?: ''), subject : (vertex.subject ?: ''), operation : (vertex.operation ?: vertex.operationEffect ?: ''), calledService : (vertex.calledService ?: ''), parameterRole : (vertex.parameterRole ?: vertex.subjectKind ?: '') ] int vertexParameterSeq = 1 vertexParameters.each { String metadataKey, Object metadataValue -> String parameterDefId = vertexParameterDefByKey[metadataKey] if (parameterDefId) { storeGraphParameter(parameterDefId, metadataValue, graphVertexId, null, vertexParameterSeq) vertexParameterSeq++ } } loadedVertexCount++ }
edgesFile.eachLine('UTF-8') { String line -> String trimmed = line?.trim() if (!trimmed) return Map edge = slurper.parseText(trimmed) as Map String rawGraphEdgeId = (edge.edgeId ?: '').toString() String rawFromVertexId = (edge.fromVertexId ?: '').toString() String rawToVertexId = (edge.toVertexId ?: '').toString() if (!rawGraphEdgeId || !rawFromVertexId || !rawToVertexId) return String graphEdgeId = normalizeEdgeId(rawGraphEdgeId) String fromVertexId = normalizeVertexId(rawFromVertexId) String toVertexId = normalizeVertexId(rawToVertexId)
