Map<String, Object> edgeParameters = [ sourceEdgeId : rawGraphEdgeId, edgeRelation : (edge.edgeType ?: existingEdge.label ?: ''), serviceName : (edge.serviceName ?: edge.artifactName ?: ''), entityName : (edge.entityName ?: ''), fieldName : (edge.fieldName ?: ''), edgeRole : (edge.role ?: edge.statementClass ?: edge.operationEffect ?: '') ] int edgeParameterSeq = 1 edgeParameters.each { String metadataKey, Object metadataValue -> String parameterDefId = edgeParameterDefByKey[metadataKey] if (parameterDefId) { storeGraphParameter(parameterDefId, metadataValue, null, graphEdgeId, edgeParameterSeq) edgeParameterSeq++ } } loadedEdgeCount++ }
loadedVertexIds.each { String graphVertexId -> def existingVertex = ec.entity.find('moqui.math.GraphVertex') .condition('graphId', effectiveGraphId) .condition('graphVertexId', graphVertexId) .one() if (existingVertex) existingVertex = existingVertex.cloneValue() if (!existingVertex) return int degree = (degreeByVertexId[graphVertexId] ?: 0) as int existingVertex.graphId = effectiveGraphId existingVertex.degree = degree existingVertex.notBelongToEdge = degree > 0 ? 'N' : 'Y' existingVertex.update() }
