int maxDegree = degreeByVertexId ? (degreeByVertexId.values().max() as Integer) : 0 int orphanVertexCount = loadedVertexIds.count { String graphVertexId -> ((degreeByVertexId[graphVertexId] ?: 0) as int) == 0 } graphStats = [ graphId : effectiveGraphId, mathModelId : effectiveMathModelId, mathModelRunId : mathModelRunId, loadedVertexCount : loadedVertexCount, loadedEdgeCount : loadedEdgeCount, maxDegree : maxDegree, orphanVertexCount : orphanVertexCount, verticesFilePath : verticesFile.canonicalPath, edgesFilePath : edgesFile.canonicalPath, summaryFilePath : summaryFilePath, summaryData : summaryData ]
