String effectiveGraphId = (graphId ?: 'AgentArtifactGraph').toString() String effectiveMathModelId = (mathModelId ?: 'AgentMoquiRagModel_v1').toString() String effectiveGraphName = (graphName ?: 'Agent Artifact Graph').toString() String effectiveGraphDescription = (graphDescription ?: 'Materialized structural graph for offline-generated Moqui agent artifacts.').toString() String effectiveGraphTypeEnumId = graphTypeEnumId ? graphTypeEnumId.toString() : null int effectiveVertexChunkSize = Math.max(1, (vertexChunkSize ?: 2000) as int) int effectiveEdgeChunkSize = Math.max(1, (edgeChunkSize ?: 5000) as int) boolean shouldCreateMathModelRun = (createMathModelRun == null) ? true : Boolean.TRUE.equals(createMathModelRun) boolean suspendedTransaction = false Path tempDir = null List<File> createdFiles = []
