try { if (!mathModelRunId && shouldCreateMathModelRun) { Map runResult = ec.service.sync().name('org.moqui.agent.AgentMathModelServices.create#AgentMathModelRun') .parameters([ mathModelId : effectiveMathModelId, runTypeEnumId : 'AgentRunArtifactGraphLoad', runName : 'Artifact Graph Load Chunked', sourceServiceName : 'org.moqui.agent.AgentDocumentServices.load#ArtifactGraphChunked', parametersJson : JsonOutput.toJson([ graphId : effectiveGraphId, verticesFilePath : verticesFilePath, edgesFilePath : edgesFilePath, summaryFilePath : summaryFilePath, clearExisting : clearExisting, vertexChunkSize : effectiveVertexChunkSize, edgeChunkSize : effectiveEdgeChunkSize ]) ]).call() mathModelRunId = runResult.mathModelRunId }
File verticesFile = new File(verticesFilePath as String) File edgesFile = new File(edgesFilePath as String) if (!verticesFile.exists()) throw new IllegalArgumentException("Artifact graph vertices file not found: ${verticesFilePath}") if (!edgesFile.exists()) throw new IllegalArgumentException("Artifact graph edges file not found: ${edgesFilePath}")
tempDir = Files.createTempDirectory('artifact-graph-load-') Closure<File> newChunkFile = { String prefix, int index -> File chunkFile = tempDir.resolve(String.format('%s-%03d.jsonl', prefix, index)).toFile() createdFiles.add(chunkFile) return chunkFile } File emptyFile = tempDir.resolve('empty.jsonl').toFile() emptyFile.text = '' createdFiles.add(emptyFile)
Closure<List<File>> splitJsonl = { File sourceFile, String prefix, int chunkSize -> List<File> chunkFiles = [] int fileIndex = 1 int lineCount = 0 File currentFile = null sourceFile.eachLine('UTF-8') { String line -> String trimmed = line?.trim() if (!trimmed) return if (currentFile == null || lineCount >= chunkSize) { currentFile = newChunkFile(prefix, fileIndex++) currentFile.text = '' chunkFiles.add(currentFile) lineCount = 0 } Files.writeString(currentFile.toPath(), trimmed + System.lineSeparator(), StandardOpenOption.APPEND) lineCount++ } return chunkFiles }
Closure<Map> runChunkLoad = { File vertexFile, File edgeFile, boolean clearFlag, String chunkLabel -> Map chunkResult = ec.service.sync().name('org.moqui.agent.AgentDocumentServices.load#ArtifactGraphChunk') .parameters([ verticesFilePath : vertexFile.absolutePath, edgesFilePath : edgeFile.absolutePath, graphId : effectiveGraphId, graphName : effectiveGraphName, graphDescription : effectiveGraphDescription, graphTypeEnumId : effectiveGraphTypeEnumId, summaryFilePath : summaryFilePath, clearExisting : clearFlag, mathModelId : effectiveMathModelId, mathModelRunId : mathModelRunId, createMathModelRun : false, completeMathModelRun : false ]).call() if (chunkResult == null) { throw new IllegalStateException("Artifact graph chunk returned null result for ${chunkLabel}") } return chunkResult }
List<File> vertexChunks = splitJsonl(verticesFile, 'vertices', effectiveVertexChunkSize) List<File> edgeChunks = splitJsonl(edgesFile, 'edges', effectiveEdgeChunkSize) vertexChunkCount = vertexChunks.size() as Integer edgeChunkCount = edgeChunks.size() as Integer
int totalLoadedVertices = 0 int totalLoadedEdges = 0 boolean shouldClear = Boolean.TRUE.equals(clearExisting) if (!vertexChunks && !edgeChunks) { Map emptyResult = runChunkLoad(emptyFile, emptyFile, shouldClear, 'empty graph') totalLoadedVertices += (emptyResult.loadedVertexCount ?: 0) as int totalLoadedEdges += (emptyResult.loadedEdgeCount ?: 0) as int }
vertexChunks.each { File vertexChunk -> Map chunkResult = runChunkLoad(vertexChunk, emptyFile, shouldClear, "vertex chunk ${vertexChunk.name}") totalLoadedVertices += (chunkResult.loadedVertexCount ?: 0) as int totalLoadedEdges += (chunkResult.loadedEdgeCount ?: 0) as int shouldClear = false }
edgeChunks.each { File edgeChunk -> Map chunkResult = runChunkLoad(emptyFile, edgeChunk, shouldClear, "edge chunk ${edgeChunk.name}") totalLoadedVertices += (chunkResult.loadedVertexCount ?: 0) as int totalLoadedEdges += (chunkResult.loadedEdgeCount ?: 0) as int shouldClear = false }
Map finalizeResult = ec.service.sync().name('org.moqui.agent.AgentDocumentServices.finalize#ArtifactGraphLoad') .parameters([ graphId : effectiveGraphId, graphName : effectiveGraphName, graphDescription : effectiveGraphDescription, graphTypeEnumId : effectiveGraphTypeEnumId, summaryFilePath : summaryFilePath, verticesFilePath : verticesFile.canonicalPath, edgesFilePath : edgesFile.canonicalPath, mathModelId : effectiveMathModelId, mathModelRunId : mathModelRunId, completeMathModelRun : true ]).call() loadedVertexCount = finalizeResult.loadedVertexCount loadedEdgeCount = finalizeResult.loadedEdgeCount graphStats = (finalizeResult.graphStats ?: [:]) as Map graphStats.chunkLoadTotals = [ loadedVertexCount : totalLoadedVertices, loadedEdgeCount : totalLoadedEdges, vertexChunkCount : vertexChunkCount, edgeChunkCount : edgeChunkCount ] } finally { createdFiles.reverseEach { File f -> try { if (f.exists()) f.delete() } catch (Throwable ignored) {} } if (tempDir != null) { try { tempDir.toFile().delete() } catch (Throwable ignored) {} } if (suspendedTransaction) ec.transaction.resume() }

import java.security.MessageDigest
String effectiveGraphId = (graphId ?: 'AgentArtifactGraph').toString() String requestedVertexId = vertexId ?: (artifactUri ?: (serviceName ? "service://${serviceName}" : documentId)) if (!requestedVertexId) { throw new IllegalArgumentException('Specify one of vertexId, artifactUri, serviceName, or documentId') } MessageDigest vertexIdDigest = MessageDigest.getInstance('SHA-1') String effectiveVertexId = vertexIdDigest.digest("${effectiveGraphId}|${requestedVertexId}".getBytes('UTF-8')).encodeHex().toString()
def vertex = ec.entity.find('moqui.math.GraphVertex') .condition('graphId', effectiveGraphId) .condition('graphVertexId', effectiveVertexId) .one() if (!vertex) { throw new IllegalArgumentException("Artifact graph vertex not found for graphId=${effectiveGraphId}, vertexId=${requestedVertexId}") }
def outgoingEdges = ec.entity.find('moqui.math.GraphEdge') .condition('graphId', effectiveGraphId) .condition('fromVertexId', effectiveVertexId) .list() def incomingEdges = ec.entity.find('moqui.math.GraphEdge') .condition('graphId', effectiveGraphId) .condition('toVertexId', effectiveVertexId) .list()
Set<String> relatedVertexIds = [] as Set<String> outgoingEdges.each { edge -> relatedVertexIds.add(edge.fromVertexId as String) relatedVertexIds.add(edge.toVertexId as String) } incomingEdges.each { edge -> relatedVertexIds.add(edge.fromVertexId as String) relatedVertexIds.add(edge.toVertexId as String) } relatedVertexIds.add(effectiveVertexId) Map<String, String> vertexLabelById = [:] if (relatedVertexIds) { ec.entity.find('moqui.math.GraphVertex') .condition('graphId', effectiveGraphId) .condition('graphVertexId', 'in', relatedVertexIds as List) .list() .each { relatedVertex -> vertexLabelById.put(relatedVertex.graphVertexId as String, (relatedVertex.label ?: relatedVertex.graphVertexId) as String) } } Closure<String> getVertexLabel = { String relatedVertexId -> if (!relatedVertexId) return null return vertexLabelById[relatedVertexId] ?: relatedVertexId }
Closure<List<Map>> edgeSummaries = { edgeList -> (edgeList ?: []).collect { edge -> [ edgeId : edge.graphEdgeId, edgeType : edge.label, fromVertexId : edge.fromVertexId, fromVertexLabel : getVertexLabel(edge.fromVertexId as String), toVertexId : edge.toVertexId, toVertexLabel : getVertexLabel(edge.toVertexId as String) ] } }
List<String> readEntities = [] List<String> writtenEntities = [] List<String> calledServices = [] List<String> usedFields = [] List<String> statementIds = [] List<String> affectedScreens = [] List<String> upstreamTransitions = []
outgoingEdges.each { edge -> String edgeLabel = edge.label as String String targetId = edge.toVertexId as String String targetLabel = getVertexLabel(targetId) if (edgeLabel == 'SERVICE_READS_ENTITY') readEntities.add(targetLabel) if (edgeLabel == 'SERVICE_WRITES_ENTITY') writtenEntities.add(targetLabel) if (edgeLabel == 'SERVICE_CALLS_SERVICE') calledServices.add(targetLabel) if (edgeLabel == 'SERVICE_USES_FIELD') usedFields.add(targetLabel) if (edgeLabel == 'SERVICE_HAS_STATEMENT') statementIds.add(targetLabel) if (edgeLabel == 'SCREEN_HAS_TRANSITION') affectedScreens.add(targetLabel) }
incomingEdges.each { edge -> String edgeLabel = edge.label as String String sourceId = edge.fromVertexId as String String sourceLabel = getVertexLabel(sourceId) if (edgeLabel == 'TRANSITION_CALLS_SERVICE') upstreamTransitions.add(sourceLabel) }
String riskLevel = writtenEntities ? 'high' : (calledServices ? 'medium' : 'low') artifactImpact = [ graphId : effectiveGraphId, requestedVertexId : requestedVertexId, vertexId : effectiveVertexId, vertexLabel : vertex.label, degree : vertex.degree, readEntities : readEntities.unique().sort(), writtenEntities : writtenEntities.unique().sort(), calledServices : calledServices.unique().sort(), usedFields : usedFields.unique().sort(), statementIds : statementIds.unique().sort(), upstreamTransitions : upstreamTransitions.unique().sort(), affectedScreens : affectedScreens.unique().sort(), outgoingEdges : edgeSummaries(outgoingEdges), incomingEdges : edgeSummaries(incomingEdges), riskLevel : riskLevel ]

import groovy.json.JsonSlurper import groovy.json.JsonOutput import org.moqui.agent.AgentConfigUtil import org.moqui.agent.search.ElasticBackendAdapter import java.security.MessageDigest
String effectiveIndex = indexName ?: AgentConfigUtil.getString('moqui.agent.prompt.indexName', 'moqui_agent_prompts_v1') String effectiveMathModelId = (mathModelId ?: 'AgentMoquiRagModel_v1').toString() String effectiveEmbeddingProvider = (embeddingProvider ?: AgentConfigUtil.getString('moqui.agent.embedding.provider', 'none')).toString() String effectiveEmbeddingModel = (embeddingModel ?: AgentConfigUtil.getString('moqui.agent.embedding.model', '')).toString() Integer effectiveEmbeddingDimensions = (embeddingDimensions ?: AgentConfigUtil.getInt('moqui.agent.embedding.dimensions', 3072, 1)) as Integer int effectiveBatchSize = Math.max(1, (batchSize ?: AgentConfigUtil.getInt('moqui.agent.index.batchSize', 250, 1)) as Integer) boolean shouldCreateMathModelRun = (createMathModelRun == null) ? true : Boolean.TRUE.equals(createMathModelRun) List paths = [] if (filePath) paths.add(filePath) if (filePathList) paths.addAll(filePathList as List) paths = paths.unique()
def nowTs = ec.user.nowTimestamp effectiveMathModelRunId = mathModelRunId if (!effectiveMathModelRunId && shouldCreateMathModelRun) { Map mathRunResult = ec.service.sync().name('org.moqui.agent.AgentMathModelServices.create#AgentMathModelRun') .parameters([ mathModelId : effectiveMathModelId, runTypeEnumId : 'AgentRunIndexing', runName : 'Agent Document Indexing', sourceServiceName : 'org.moqui.agent.AgentDocumentServices.index#AgentDocuments', parametersJson : JsonOutput.toJson([ indexName : effectiveIndex, documentSchemaVersion : documentSchemaVersion ?: 'screen-first-v1', embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions : effectiveEmbeddingDimensions, batchSize : effectiveBatchSize, filePathList : paths ]) ]).call() effectiveMathModelRunId = mathRunResult.mathModelRunId } def runValue = ec.entity.makeValue('moqui.agent.AgentDocumentIndexRun') runValue.setSequencedIdPrimary() agentDocumentIndexRunId = runValue.getString('agentDocumentIndexRunId') runValue.setAll([ mathModelRunId : effectiveMathModelRunId, indexName : effectiveIndex, documentSchemaVersion : documentSchemaVersion ?: 'screen-first-v1', embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions : effectiveEmbeddingDimensions, startedDate : nowTs, statusId : 'IndexingRunning', reportLocation : reportLocation ?: (paths ? paths.join(',') : null) ]) runValue.create()
def adapter = new ElasticBackendAdapter(ec) if (Boolean.TRUE.equals(forceReindex) && adapter.indexExists(effectiveIndex)) { adapter.deleteIndex(effectiveIndex) }
def slurper = new JsonSlurper() def hashDigest = MessageDigest.getInstance('SHA-256')
indexedCount = 0 failedCount = 0 int readCount = 0 int embeddedCount = 0 int embeddingSkippedCount = 0 int embeddingFailedCount = 0
try { if (!adapter.indexExists(effectiveIndex)) { Map mappingResult = ec.service.sync().name('org.moqui.agent.AgentDocumentServices.transform#AgentPromptDocumentMapping') .parameters([ mapping : [:] ]).call() adapter.createIndex(effectiveIndex, [mappings: mappingResult['mapping'], settings: mappingResult['settings']]) }
Closure updateRunMetrics = { metrics = [ indexName : effectiveIndex, mathModelId : effectiveMathModelId, mathModelRunId : effectiveMathModelRunId, readCount : readCount, indexedCount : indexedCount, failedCount : failedCount, fileCount : paths.size(), batchSize : effectiveBatchSize, documentSchemaVersion : runValue.documentSchemaVersion, indexingPath : 'AgentDocumentServices.fastPath.batched', embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions : effectiveEmbeddingDimensions, embeddedCount : embeddedCount, embeddingSkippedCount : embeddingSkippedCount, embeddingFailedCount : embeddingFailedCount ] runValue.metricsJson = JsonOutput.toJson(metrics) runValue.update() if (effectiveMathModelRunId) { ec.service.sync().name('org.moqui.agent.AgentMathModelServices.update#AgentMathModelRunMetrics') .parameters([ mathModelRunId : effectiveMathModelRunId, metricsJson : JsonOutput.toJson(metrics), statusId : runValue.statusId ]).call() } }
Closure normalizeNestedField = { Map doc, String fieldName, Closure mapper -> Object rawValue = doc.get(fieldName) if (rawValue == null) { doc.put(fieldName, []) return } if (!(rawValue instanceof List)) { rawValue = [rawValue] } List normalizedList = [] ((List) rawValue).each { Object entry -> if (entry == null) return if (entry instanceof Map) { normalizedList.add(new LinkedHashMap((Map) entry)) return } Map mappedEntry = mapper(entry) if (mappedEntry) normalizedList.add(mappedEntry) } doc.put(fieldName, normalizedList) }
Closure normalizeNestedArtifacts = { Map doc -> normalizeNestedField(doc, 'sourceArtifacts', { Object entry -> [artifactName: entry?.toString()] }) normalizeNestedField(doc, 'executableArtifacts', { Object entry -> [artifactName: entry?.toString()] }) normalizeNestedField(doc, 'preferredServiceRules', { Object entry -> [reason: entry?.toString()] }) normalizeNestedField(doc, 'uiActions', { Object entry -> [label: entry?.toString()] }) normalizeNestedField(doc, 'ecaSummaries', { Object entry -> [summary: entry?.toString()] }) }
Closure enrichAndIndexBatch = { List<Map> docsBatch -> if (!docsBatch) return docsBatch.each { Map doc -> normalizeNestedArtifacts.call(doc) if (doc.embedding instanceof List && !((doc.embedding as List).isEmpty())) return String embeddingText = ((doc.embeddingText ?: doc.canonicalPrompt ?: '') as String).trim() if (!embeddingText) { embeddingSkippedCount++ return } if (!effectiveEmbeddingProvider || effectiveEmbeddingProvider == 'none') { embeddingSkippedCount++ return } try { Map embeddingResult = ec.service.sync().name('org.moqui.agent.AgentDocumentServices.get#QueryEmbedding').parameters([ queryText : embeddingText, embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions : effectiveEmbeddingDimensions ]).call() List embeddingVector = (embeddingResult.embedding instanceof List) ? embeddingResult.embedding as List : [] if (embeddingVector) { doc.embedding = embeddingVector embeddedCount++ } else { embeddingFailedCount++ } } catch (Throwable embeddingThrowable) { embeddingFailedCount++ ec.logger.warn("Could not generate embedding for agent document ${doc.documentId ?: doc._id}: ${embeddingThrowable.message}") } }
try { adapter.bulkIndex(effectiveIndex, docsBatch) indexedCount += docsBatch.size() updateRunMetrics.call() } catch (Throwable batchThrowable) { failedCount += docsBatch.size() updateRunMetrics.call() throw batchThrowable } }
boolean anyDocRead = false paths.each { String path -> File file = new File(path) if (!file.exists()) return List<Map> currentBatch = [] file.eachLine('UTF-8') { String line -> hashDigest.update((line + '\n').getBytes('UTF-8')) String trimmed = line?.trim() if (!trimmed) return Map doc = slurper.parseText(trimmed) as Map if (!doc.documentId && doc._id) doc.documentId = doc._id currentBatch.add(doc) readCount++ anyDocRead = true if (currentBatch.size() >= effectiveBatchSize) { enrichAndIndexBatch.call(currentBatch) currentBatch = [] } } if (currentBatch) enrichAndIndexBatch.call(currentBatch) }
if (!anyDocRead) { metrics = [indexName: effectiveIndex, indexedCount: 0, fileCount: paths.size(), batchSize: effectiveBatchSize] runValue.statusId = 'IndexingEmpty' runValue.completedDate = ec.user.nowTimestamp runValue.metricsJson = JsonOutput.toJson(metrics) runValue.artifactVersionHash = hashDigest.digest().encodeHex().toString() runValue.update() if (effectiveMathModelRunId) { ec.service.sync().name('org.moqui.agent.AgentMathModelServices.complete#AgentMathModelRun') .parameters([ mathModelRunId : effectiveMathModelRunId, resultSummaryJson : JsonOutput.toJson(metrics) ]).call() } return }
metrics = [ indexName : effectiveIndex, readCount : readCount, indexedCount : indexedCount, failedCount : failedCount, fileCount : paths.size(), batchSize : effectiveBatchSize, documentSchemaVersion: runValue.documentSchemaVersion, indexingPath : 'AgentDocumentServices.fastPath.batched', embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions: effectiveEmbeddingDimensions, embeddedCount : embeddedCount, embeddingSkippedCount: embeddingSkippedCount, embeddingFailedCount: embeddingFailedCount ] runValue.statusId = 'IndexingComplete' } catch (Throwable t) { metrics = [ indexName : effectiveIndex, readCount : readCount, indexedCount: indexedCount, failedCount : failedCount, fileCount : paths.size(), batchSize : effectiveBatchSize, embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions: effectiveEmbeddingDimensions, embeddedCount : embeddedCount, embeddingSkippedCount: embeddingSkippedCount, embeddingFailedCount: embeddingFailedCount, error : t.message ] runValue.statusId = 'IndexingFailed' if (effectiveMathModelRunId) { ec.service.sync().name('org.moqui.agent.AgentMathModelServices.fail#AgentMathModelRun') .parameters([ mathModelRunId : effectiveMathModelRunId, errorMessage : t.message, metricsJson : JsonOutput.toJson(metrics) ]).call() } throw t } finally { runValue.completedDate = ec.user.nowTimestamp runValue.metricsJson = JsonOutput.toJson(metrics ?: [:]) runValue.artifactVersionHash = hashDigest.digest().encodeHex().toString() runValue.update() if (runValue.statusId == 'IndexingComplete' && effectiveMathModelRunId) { ec.service.sync().name('org.moqui.agent.AgentMathModelServices.complete#AgentMathModelRun') .parameters([ mathModelRunId : effectiveMathModelRunId, resultSummaryJson : JsonOutput.toJson(metrics) ]).call() ec.service.sync().name('org.moqui.agent.AgentMathModelServices.register#AgentEmbeddingTensor') .parameters([ mathModelId : effectiveMathModelId, mathModelRunId : effectiveMathModelRunId, indexName : effectiveIndex, embeddingProvider : effectiveEmbeddingProvider, embeddingModel : effectiveEmbeddingModel, embeddingDimensions : effectiveEmbeddingDimensions, documentCount : indexedCount, contentLocation : "opensearch://${effectiveIndex}/embedding", contentFormat : 'opensearch-knn' ]).call() } }
